#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;

struct Node{
    int id,val;
};

bool operator<(Node x,Node y){
    return x.val>y.val;
}

int n,k,d[N],nxt[N],pre[N],a[N],ans;
bool del[N];
priority_queue<Node> q;

void Delet(int x){
    if(!x)
        return;
    if(nxt[x])
        pre[nxt[x]]=pre[x];
    if(pre[x])
        nxt[pre[x]]=nxt[x];
    del[x]=1;
}

int main(){
    scanf("%d%d",&n,&k);
    for(int i=1;i<=n;i++){
        scanf("%d",&d[i]);
        if(i>1)
            a[i-1]=d[i]-d[i-1],q.push({i-1,d[i]-d[i-1]});
    }
    n--;
    for(int i=1;i<=n;i++)
        nxt[i]=(i+1)%(n+1),pre[i]=i-1;
    for(int i=1;i<=k;i++){
        while(del[q.top().id])
            q.pop();
        Node tmp=q.top();
        q.pop(),ans+=tmp.val;
        if(nxt[tmp.id] && pre[tmp.id]){
            a[tmp.id]=a[pre[tmp.id]]+a[nxt[tmp.id]]-a[tmp.id];
            Delet(pre[tmp.id]),Delet(nxt[tmp.id]),q.push({tmp.id,a[tmp.id]});
        }else
            Delet(pre[tmp.id]),Delet(nxt[tmp.id]),Delet(tmp.id);
    }
    printf("%d",ans);
    return 0;
}
